#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <stdbool.h>

bool is_keyword(const char *s){
    const char *kw[] = {"False","await","else","import","pass","None","break","except","in","raise","True","class","finally","is","return","and","continue","for","lambda","try","as","def","from","nonlocal","while","assert","del","global","not","with","async","elif","if","or","yield"};
    for(int i=0;i<33;i++) if(strcmp(s,kw[i])==0) return true;
    return false;
}

bool is_identifier(const char *s){
    if(!(isalpha((unsigned char)s[0])||s[0]=='_')) return false;
    for(int i=1;s[i];i++) if(!(isalnum((unsigned char)s[i])||s[i]=='_')) return false;
    return !is_keyword(s);
}

const char* classify(const char *s){
    if((strncmp(s,"http://",7)==0 && strlen(s)>7) || (strncmp(s,"https://",8)==0 && strlen(s)>8))
        return "URL";
    int at_cnt=0; const char *at_ptr=NULL;
    for(const char *p=s;*p;p++) if(*p=='@'){at_cnt++; at_ptr=p;}
    if(at_cnt==1){
        int local_len = at_ptr - s;
        const char *domain = at_ptr+1;
        int domain_len = strlen(domain);
        if(local_len>0 && domain_len>0 && strchr(domain,'.') && domain[0]!='.' && domain[domain_len-1]!='.')
            return "Email";
    }
    if(is_identifier(s)) return "Identifier";
    return "Invalid";
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar();
    char buf[105];
    for(int i=0;i<T;i++){
        if(fgets(buf,105,stdin)==NULL) break;
        size_t len=strlen(buf);
        if(len && buf[len-1]=='\n') buf[len-1]='\0';
        printf("%s\n", classify(buf));
    }
    return 0;
}

