import java.io.*;
import java.util.*;
public class Main {
    private static final Set<String> KEYWORDS = new HashSet<>(Arrays.asList(
        "False","await","else","import","pass","None","break","except","in","raise",
        "True","class","finally","is","return","and","continue","for","lambda","try",
        "as","def","from","nonlocal","while","assert","del","global","not","with",
        "async","elif","if","or","yield"));
    private static boolean isIdentifier(String s){
        if(s.isEmpty()) return false;
        char c=s.charAt(0);
        if(!(Character.isLetter(c)||c=='_')) return false;
        for(int i=1;i<s.length();i++){
            c=s.charAt(i);
            if(!(Character.isLetterOrDigit(c)||c=='_')) return false;
        }
        return !KEYWORDS.contains(s);
    }
    private static String classify(String s){
        if((s.startsWith("http://") && s.length()>7) || (s.startsWith("https://") && s.length()>8))
            return "URL";
        if(s.chars().filter(ch->ch=='@').count()==1){
            int at=s.indexOf('@');
            String local=s.substring(0,at);
            String domain=s.substring(at+1);
            if(!local.isEmpty() && !domain.isEmpty() && domain.contains(".") && !domain.startsWith(".") && !domain.endsWith("."))
                return "Email";
        }
        if(isIdentifier(s)) return "Identifier";
        return "Invalid";
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder sb=new StringBuilder();
        for(int i=0;i<T;i++){
            String line=br.readLine();
            sb.append(classify(line)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

