import sys, keyword

def classify(s: str) -> str:
    if (s.startswith('http://') and len(s) > 7) or (s.startswith('https://') and len(s) > 8):
        return 'URL'
    if s.count('@') == 1:
        local, domain = s.split('@')
        if local and domain and '.' in domain and not domain.startswith('.') and not domain.endswith('.'):
            return 'Email'
    if s.isidentifier() and not keyword.iskeyword(s):
        return 'Identifier'
    return 'Invalid'

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        out.append(classify(data[i].strip()))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

